protected String[] flatten(Options options, String[] arguments, boolean stopAtNonOption)
{
    init();
    this.options = options;

    // an iterator for the command line tokens
    Iterator<String> iter = Arrays.asList(arguments).iterator();

    // process each command line token
    while (iter.hasNext())
    {
        // get the next command line token
        String token = iter.next();

        // handle long option --foo or --foo=bar
        if (token.startsWith("--"))
        {
            if (token.contains("=") && token.indexOf('=') != 2 )
            {
                tokens.add(token.substring(0, token.indexOf('=')));
                tokens.add(token.substring(token.indexOf('=') + 1));
            }
            else if (!options.hasLongOpt(token.substring(2))) 
            {
                tokens.add(token);
                 gobble(iter);
                continue;

            }
            else
            {
                tokens.add(token);
            }
        }

        // single hyphen
        else if ("-".equals(token))
        {
            tokens.add(token);
        }
        else if (token.startsWith("-"))
        {
            if (token.length() > 2) 
            {
                List<String> subTokens = new ArrayList<>();
                for (int i = 1 ; i < token.length() ; i ++)
                    subTokens.add(Character.toString(token.charAt(i)));
               for (String subToken : subTokens){
                   if (options.hasOption(subToken)){
                        tokens.add("-" + subToken);
                   }else if (stopAtNonOption){
                       iter = Arrays.asList(new String[]{token}).iterator();
                       break;
                   }else{
                       tokens.add(token);
                   }

                }

                  gobble(iter);
                continue;
            }



        }
        else if (stopAtNonOption)
        {
            tokens.add(token);
           gobble(iter);
            continue;
        }
        else
        {
            tokens.add(token);
        }
         gobble(iter);
    }

    return (String[]) tokens.toArray(new String[tokens.size()]);
}
private void gobble(Iterator iter){
    if(iter.hasNext()){
       iter.next();
    }
}

